function displayProducts(products) {
    let productConatiner = document.getElementById('product-container')
    console.log(productConatiner)
    productConatiner.innerHTML = products.map((item) => `
        <aside class="product-card">
            <img src="${item.image}" alt="">
            <h3>${item.name}</h3>
            <p>₹ ${item.price}</p>
            <button onclick="addToCart(${item.id})">Add to cart</button>
        </aside>
    `).join('')
}
displayProducts(products)



function filterCategory(cat) {
    if (cat === "all") {
        displayProducts(products)
    } else {
        let filterData = products.filter((f => f.category === cat))
        console.log(filterData)
        displayProducts(filterData)
    }
}



function addToCart(id){
    let cart=JSON.parse(localStorage.getItem('cart'))||[]
    console.log(cart)
    let item=products.find((f)=>f.id===id)
    cart.push(item)
    localStorage.setItem('cart',JSON.stringify(cart))
    alert(`${item.name} added to cart`)
}